const payload = $json.body ?? $json;

const cab = payload.cabecalho ?? {};
const produtos = payload.produtos?.Produtos ?? [];

function parseBRDate(str) {
  if (!str || typeof str !== 'string') return null;
  const [dd, mm, yyyy] = str.split('/');
  if (!dd || !mm || !yyyy) return null;
  return new Date(Number(yyyy), Number(mm) - 1, Number(dd), 12, 0, 0);
}

function formatDateShort(date) {
  const dd = String(date.getDate()).padStart(2, '0');
  const mm = String(date.getMonth() + 1).padStart(2, '0');
  const yy = String(date.getFullYear()).slice(-2);
  return `${dd}/${mm}/${yy}`;
}

function getWeekdayPt(date) {
  const dias = [
    'domingo',
    'segunda-feira',
    'terça-feira',
    'quarta-feira',
    'quinta-feira',
    'sexta-feira',
    'sábado'
  ];
  return dias[date.getDay()];
}

function diffInDays(fromDate, toDate) {
  const a = new Date(fromDate.getFullYear(), fromDate.getMonth(), fromDate.getDate(), 12, 0, 0);
  const b = new Date(toDate.getFullYear(), toDate.getMonth(), toDate.getDate(), 12, 0, 0);
  return Math.round((b - a) / 86400000);
}

function getPrazoText(dataEntrega) {
  if (!dataEntrega) return '';
  const hoje = new Date();
  const diff = diffInDays(hoje, dataEntrega);
  const weekday = getWeekdayPt(dataEntrega);
  const dataFmt = formatDateShort(dataEntrega);

  let sufixo = '';
  if (diff < 0) {
    const abs = Math.abs(diff);
    sufixo = `(Atrasado há ${abs} ${abs === 1 ? 'dia' : 'dias'})`;
  } else if (diff === 0) {
    sufixo = '(Hoje)';
  } else if (diff === 1) {
    sufixo = '(Amanhã)';
  } else {
    sufixo = `(Daqui a ${diff} dias)`;
  }

  return `${weekday}, ${dataFmt} ${sufixo}`;
}

function getPrioridade(diff) {
  if (diff <= 1) return '🔴 *URGENTE*';
  if (diff >= 2 && diff <= 3) return '🟠 *ALTA*';
  if (diff >= 4 && diff <= 5) return '🟡 *MÉDIA*';
  return '🟢 *NORMAL*';
}

function cleanText(str) {
  return String(str ?? '')
    .replace(/[“”"]/g, '')
    .replace(/\s+/g, ' ')
    .replace(/\s+\)/g, ')')
    .replace(/\(\s+/g, '(')
    .trim();
}

function formatQty(qtd) {
  const texto = String(qtd ?? '').trim();
  return texto || '1';
}

const dataEntrega = parseBRDate(cab['Data de entrega']);
const hoje = new Date();
const diffDias = dataEntrega ? diffInDays(hoje, dataEntrega) : null;

const prazoLinha = dataEntrega ? getPrazoText(dataEntrega) : 'Sem data de entrega';
const prioridadeLinha = diffDias === null ? '🟢 *NORMAL*' : getPrioridade(diffDias);

const itensTexto = produtos.map((item) => {
  const qtd = formatQty(item.quantidade);
  const nome = cleanText(item.nome_item_mensagem || '') || 'Item sem descrição';

  return `▪️${qtd}x ${nome}`;
}).join('\n');

const osNum = cleanText(payload.os_num || cab['Nº OS']);
const cliente = cleanText(cab['Cliente']);
const ref = cleanText(cab['Ref. (nome do trabalho)']);
const orcamentista = cleanText(cab['Orçamentista/atendente']);
const vendedor = cleanText(cab['Vendedor']);

const driveUrl = payload.folder_id
  ? '{{URL_REDACTED_DRIVE_FOLDER}}'
  : '';

const trelloUrl = '{{URL_REDACTED_TRELLO_BOARD}}';

const titulo = [`#${osNum}`, cliente, ref].filter(Boolean).join(' | ');

const mensagemWhatsApp = [
  '━━━━━━━━━━━━━━━━━━',
  '📌 *ORDEM DE SERVIÇO REGISTRADA*',
  `*${titulo}*`,
  '━━━━━━━━━━━━━━━━━━',
  '',
  `📅 *Prazo:* *${prazoLinha}*`,
  `*Prioridade:* ${prioridadeLinha}`,
  '',
  `📑 *Orçamentista:* ${orcamentista || '-'}`,
  `🤝 *Vendedor:* ${vendedor || '-'}`,
  '',
  '📦 *Itens:*',
  itensTexto || '▪️Sem itens',
  '',
  `📁 *Arquivos:* ${driveUrl}`,
  `🗂️ *Trello:* ${trelloUrl}`,
  '',
  '━━━━━━━━━━━━━━━━━━'
].join('\n');

return {
  json: {
    ...$json,
    prazo_linha: prazoLinha,
    prioridade_linha: prioridadeLinha,
    dias_para_entrega: diffDias,
    itens_texto: itensTexto,
    drive_url: driveUrl,
    trello_url: trelloUrl,
    mensagem_whatsapp: mensagemWhatsApp
  }
};

const body = $json.body ?? {};
const produtos = body.produtos?.Produtos ?? [];

function cleanText(str) {
  return String(str ?? '')
    .replace(/[“”"]/g, '')
    .replace(/[‘’']/g, '')
    .replace(/\?/g, ' ')
    .replace(/\s+/g, ' ')
    .replace(/\(\s+/g, '(')
    .replace(/\s+\)/g, ')')
    .replace(/\[\s+/g, '[')
    .replace(/\s+\]/g, ']')
    .trim();
}

function normalizeBareWord(word) {
  return String(word ?? '')
    .toLowerCase()
    .replace(/^[^a-zà-ÿ]+/i, '')
    .replace(/[^a-zà-ÿ]+$/i, '');
}

function capitalizeToken(token) {
  const lower = token.toLowerCase();

  return lower.replace(/^([^a-zà-ÿ]*)([a-zà-ÿ])/i, (_, prefix, first) => {
    return prefix + first.toUpperCase();
  });
}

function toSmartTitle(str) {
  const stopWords = new Set([
    'de', 'da', 'do', 'das', 'dos', 'e', 'em', 'na', 'no', 'nas', 'nos',
    'para', 'por', 'com', 'sem', 'a', 'o', 'as', 'os'
  ]);

  return cleanText(str)
    .split(' ')
    .map((word, index) => {
      if (!word) return word;

      const bare = normalizeBareWord(word);

      if (index > 0 && stopWords.has(bare)) {
        return word.toLowerCase();
      }

      return capitalizeToken(word);
    })
    .join(' ')
    .replace(/\(\s+/g, '(')
    .replace(/\s+\)/g, ')')
    .trim();
}

function removeItemPrefix(texto) {
  return texto.replace(/^item\s*\d+(?:\.\d+)?\s*[-:–]?\s*/i, '').trim();
}

function splitMultiDeliverables(texto) {
  return texto
    .split(/\s+\+\s+|\s*;\s*/i)
    .map(t => cleanText(t))
    .filter(Boolean);
}

function pickSubitemSegment(texto, subitem) {
  const match = String(subitem ?? '').match(/\.(\d+)$/);
  if (!match) return texto;

  const idx = Number(match[1]) - 1;
  const partes = splitMultiDeliverables(texto);

  if (partes.length > 1 && partes[idx]) {
    return partes[idx];
  }

  return texto;
}

function cutAtPipe(texto) {
  const idx = texto.indexOf('|');
  if (idx >= 0) {
    return texto.slice(0, idx).trim();
  }
  return texto;
}

function cutAtFirstMarker(texto) {
  const markers = [
    /\bverificar\b/i,
    /\bnecessidade\b/i,
    /\bsendo\b/i,
    /\bobserva(?:cao|ção|coes|ções)\b/i,
    /\bobs\b/i,
    /\blocal\b/i,
    /\btamanho\b/i,
    /\btamanhos\b/i,
    /\bformato\b/i,
    /\bimpresso\b/i,
    /\bimpressa\b/i,
    /\bproduzido\b/i,
    /\bproduzida\b/i,
    /\bacabamentos?\b/i
  ];

  let corte = texto.length;

  for (const regex of markers) {
    const match = regex.exec(texto);
    if (match && match.index >= 0 && match.index < corte) {
      corte = match.index;
    }
  }

  return texto.slice(0, corte).trim();
}

function removeQtyNoise(texto) {
  return texto
    .replace(/\b\d+\s*unidades?\b/gi, ' ')
    .replace(/\b\d+\s*x\b/gi, ' ')
    .replace(/\s*[-–:|]+\s*$/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function fallbackName(item) {
  const produto = cleanText(item.produto);
  const modelo = cleanText(item.modelo);

  if (item.subitem) {
    return cleanText(modelo || produto || 'Subitem');
  }

  return cleanText(produto || modelo || 'Item');
}

function buildNomeItem(item) {
  let texto = cleanText(item.descricao_cliente);

  texto = removeItemPrefix(texto);

  if (item.subitem) {
    texto = pickSubitemSegment(texto, item.subitem);
  }

  // REGRA IMPORTANTE:
  // se houver pipe, tudo após ele é detalhe técnico/observação
  texto = cutAtPipe(texto);

  texto = cutAtFirstMarker(texto);
  texto = removeQtyNoise(texto);

  texto = cleanText(texto)
    .replace(/\s*[:\-–|]+\s*$/g, '')
    .trim();

  if (!texto || texto.length < 3) {
    texto = fallbackName(item);
  }

  return toSmartTitle(texto);
}

const produtosTratados = produtos.map((item) => ({
  ...item,
  nome_item_mensagem: buildNomeItem(item)
}));

return {
  json: {
    ...$json,
    body: {
      ...body,
      produtos: {
        ...(body.produtos ?? {}),
        Produtos: produtosTratados
      }
    }
  }
};

const payload = $json.body ?? $json;
const cab = payload.cabecalho ?? {};

function cleanText(str) {
  return String(str ?? '').trim();
}

function mapCategoria(tipoOS) {
  const valor = cleanText(tipoOS).toLowerCase();

  if (valor === 'instalado') return 'Instalação';
  if (valor === 'entrega própria') return 'Entrega';
  if (valor === 'cliente retira') return 'Retirada';

  return '';
}

return {
  json: {
    ...$json,
    responsavel_planilha: '{{RESPONSAVEL_EXEMPLO}}',
    cliente_planilha: cleanText(cab['Cliente']),
    demanda_planilha: cleanText(cab['Ref. (nome do trabalho)']),
    status_planilha: 'ATENÇÃO! DEFINIR STATUS',
    transporte_planilha: 'ATENÇÃO! DEFINIR TRANSPORTE',
    horario_planilha: cleanText(cab['Hora de entrega']),
    categoria_planilha: mapCategoria(cab['Tipo de OS']),
    entrega_planilha: cleanText(cab['Data de entrega']),
    instalador_planilha: 'ATENÇÃO! DEFINIR INSTALADOR',
    os_planilha: cleanText(cab['Nº OS'])
  }
};

const linhaNova = $('Preparar linha planilha').first().json;
const rows = $input.all().map(item => item.json);

const firstDataRow = 2;

function hasValue(v) {
  return String(v ?? '').trim() !== '';
}

// Considera ocupada somente a linha que já tem OS preenchida
const occupiedRows = rows
  .filter(r => hasValue(r.OS))
  .map(r => Number(r.row_number))
  .filter(n => Number.isInteger(n) && n >= firstDataRow)
  .sort((a, b) => a - b);

let targetRow = firstDataRow;

for (const rowNum of occupiedRows) {
  if (rowNum === targetRow) {
    targetRow++;
    continue;
  }

  if (rowNum > targetRow) {
    break;
  }
}

return [
  {
    json: {
      ...linhaNova,
      target_row_number: targetRow
    }
  }
];

const payload = $json.body ?? $json;
const cab = payload.cabecalho ?? {};
const produtos = payload.produtos?.Produtos ?? [];

function clean(str) {
  return String(str ?? '').trim() || null;
}

function parseBRDate(str) {
  if (!str || typeof str !== 'string') return null;
  const parts = str.split('/');
  if (parts.length !== 3) return null;
  const [dd, mm, yyyy] = parts;
  return `${yyyy}-${mm.padStart(2,'0')}-${dd.padStart(2,'0')}`;
}

function extractNumOS(raw) {
  const s = String(raw ?? '').trim();
  const m = s.match(/(\d+)/);
  return m ? Number(m[1]) : null;
}

function formatDimensoes(dim) {
  if (!dim) return null;
  if (typeof dim === 'string') return dim || null;
  const l = dim.largura || dim.width || '';
  const a = dim.altura || dim.height || '';
  if (!l && !a) return null;
  const e = dim.espessura || dim.depth || '';
  return e ? `${l} x ${a} x ${e}` : `${l} x ${a}`;
}

const numOs = extractNumOS(cab['N\u00ba OS'] ?? cab['N OS'] ?? cab['num_os']);
if (!numOs) {
  return { json: { skip: true, reason: 'sem num_os' } };
}

function formatDateBR(dateStr) {
  if (!dateStr) return null;

  // já veio em YYYY-MM-DD
  if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
    const [y, m, d] = dateStr.split('-');
    return `${d}/${m}/${y}`;
  }

  // já veio em DD/MM/YYYY
  if (/^\d{2}\/\d{2}\/\d{4}$/.test(dateStr)) {
    return dateStr;
  }

  return dateStr;
}

const osRow = {
  num_os: numOs,
  referencia: clean(cab['Ref. (nome do trabalho)'] ?? cab['referencia']),
  cliente_nome_original: clean(cab['Cliente'] ?? cab['cliente']),
  cnpj_cliente: clean(cab['CNPJ/CPF'] ?? cab['cnpj_cliente']),
  contato: clean(cab['Contato'] ?? cab['contato']),
  telefone_contato: clean(cab['Telefone do contato'] ?? cab['telefone_contato']),
  endereco: clean(cab['Local de instalação'] ?? cab['endereco']),
  obs_os: clean(cab['Observações da O.S.'] ?? cab['obs_os']),
  vendedor: clean(cab['Vendedor'] ?? cab['vendedor']),
  atendente: clean(cab['Atendente'] ?? cab['atendente'] ?? cab['Orçamentista/atendente']),
  data_entrega: parseBRDate(cab['Data de entrega']) ?? clean(cab['data_entrega']),
  hora_entrega: clean(cab['Hora de entrega']) ?? clean(cab['hora_entrega']),
  data_aprovacao: parseBRDate(cab['Data de aprovação'] ?? cab['Data de aprovacao']) ?? clean(cab['data_aprovacao']),
  hora_aprovacao: clean(cab['Hora de aprovação']) ?? clean(cab['hora_aprovacao']),
  logistica: clean(cab['Tipo de OS'] ?? cab['logistica']),
  autorizado_por: clean(cab['Autorizado por'] ?? cab['autorizado_por']),
  data_autorizacao: parseBRDate(cab['Data de aprovação'] ?? cab['Data de autorizacao']) ?? clean(cab['data_autorizacao']),
  data_entrega_br: formatDateBR(parseBRDate(cab['Data de entrega']) ?? clean(cab['data_entrega'])),
  data_aprovacao_br: formatDateBR(parseBRDate(cab['Data de aprovação']) ?? cab['Data de aprovacao'] ?? clean(cab['data_aprovacao'])),
  data_autorizacao_br: formatDateBR(parseBRDate(cab['Data de aprovação'] ?? cab['Data de autorizacao']) ?? clean(cab['data_autorizacao'])),
  formato_pdf: 'n8n_webhook',
  num_itens: produtos.length,
  fonte: 'chronos'
};

const itens = produtos.map((p, idx) => {
  const sub = String(p.subitem ?? '').trim();
  const itemNum = sub ? (Number(sub) || (idx + 1)) : (idx + 1);
  return {
    num_os: numOs,
    item_num: itemNum,
    descricao_cliente: clean(p.descricao_cliente ?? p.nome_item_mensagem),
    quantidade: p.quantidade ? Number(p.quantidade) : null,
    tamanhos: formatDimensoes(p.dimensoes) ?? clean(p.tamanhos ?? p.medidas),
    fonte: 'chronos'
  };
});

return {
  json: {
    skip: false,
    os: osRow,
    itens: itens
  }
};

function toTimestamptz(dateStr, timeStr, offset = '-03:00') {
  if (!dateStr || !timeStr) return null;

  const date = String(dateStr).trim();
  const time = String(timeStr).trim();

  // aceita HH:mm ou HH:mm:ss
  const timeFull = /^\d{2}:\d{2}$/.test(time) ? `${time}:00` : time;

  // entrada esperada: YYYY-MM-DD
  if (/^\d{4}-\d{2}-\d{2}$/.test(date)) {
    return `${date}T${timeFull}${offset}`;
  }

  // fallback caso venha em DD/MM/YYYY
  if (/^\d{2}\/\d{2}\/\d{4}$/.test(date)) {
    const [d, m, y] = date.split('/');
    return `${y}-${m}-${d}T${timeFull}${offset}`;
  }

  return null;
}

return items.map(item => {
  const j = item.json;
  const os = j.os || {};

  return {
    json: {
      ...j,
      data_aprovacao_ts: toTimestamptz(os.data_aprovacao, os.hora_aprovacao),
      data_entrega_ts: toTimestamptz(os.data_entrega, os.hora_entrega),
    }
  };
});

function splitDescricaoObservacao(texto) {
  if (!texto) {
    return {
      descricao_cliente: null,
      observacoes_item: null,
    };
  }

  const s = String(texto).replace(/\s+/g, ' ').trim();

  const gatilhos = [
    /\bVERIFICAR\b/i,
    /\bNECESSIDADE\s*:/i,
    /\bOBS\b\s*[:.-]/i,
    /\bOBSERVA(C|Ç)(A|Ã)O\b/i,
    /\bCONFIRMAR\b/i,
    /\bMEDIR\b/i,
    /\bCHECAR\b/i,
    /\bNA CASA\b/i,
    /\bNO LOCAL\b/i,
    /\bINSTALA(C|Ç)(A|Ã)O\b/i,
    /\bDESINSTALA(C|Ç)(A|Ã)O\b/i,
  ];

  let pos = -1;

  for (const rgx of gatilhos) {
    const m = s.match(rgx);
    if (m && m.index !== undefined) {
      if (pos === -1 || m.index < pos) pos = m.index;
    }
  }

  if (pos === -1) {
    return {
      descricao_cliente: s,
      observacoes_item: null,
    };
  }

  return {
    descricao_cliente: s.slice(0, pos).trim().replace(/[| -]+$/, '').trim(),
    observacoes_item: s.slice(pos).trim(),
  };
}

function toNumberOrNull(v) {
  if (v === undefined || v === null || v === '') return null;
  const n = Number(String(v).replace(',', '.').replace(/[^\d.-]/g, ''));
  return Number.isFinite(n) ? n : null;
}

function montarTamanho(dim) {
  if (!dim || typeof dim !== 'object') return null;

  const partes = [
    dim.largura,
    dim.altura,
    dim.espessura,
  ]
    .map(v => (v ?? '').toString().trim())
    .filter(v => v !== '');

  return partes.length ? partes.join(' x ') : null;
}

const payload = $('Webhook').first().json.body;
const produtos = payload?.produtos?.Produtos ?? [];
const numOs = toNumberOrNull(payload?.os_num ?? payload?.cabecalho?.['Nº OS']);

const descricaoPaiMap = new Map();

for (const p of produtos) {
  const codigoPai = String(p.codigo_item_pai ?? p.codigo_item ?? '').trim();
  const codigoItem = String(p.codigo_item ?? '').trim();
  const temSubitem = String(p.subitem ?? '').trim() !== '';

  if (!descricaoPaiMap.has(codigoPai)) {
    descricaoPaiMap.set(codigoPai, p.descricao_cliente ?? null);
  }

  // se existir item pai "4" explícito, prioriza ele como descrição base
  if (!temSubitem && codigoItem === codigoPai && (p.descricao_cliente ?? '').trim()) {
    descricaoPaiMap.set(codigoPai, p.descricao_cliente);
  }
}

return produtos.map((p) => {
  const codigoItem = String(p.codigo_item ?? '').trim();
  const codigoPai = String(p.codigo_item_pai ?? p.codigo_item ?? '').trim();
  const subitem = String(p.subitem ?? '').trim();

  const itemNumPai = Number(codigoPai.split('.')[0]);

  const descricaoBase = descricaoPaiMap.get(codigoPai) ?? p.descricao_cliente ?? null;
  const partesTexto = splitDescricaoObservacao(descricaoBase);

  return {
    json: {
      num_os: numOs,
      item_num: Number.isFinite(itemNumPai) ? itemNumPai : null,
      descricao_cliente: partesTexto.descricao_cliente,
      observacoes_item: partesTexto.observacoes_item,
      quantidade: toNumberOrNull(p.quantidade),
      tamanhos: montarTamanho(p.dimensoes),
      subitens: {
        codigo_item: codigoItem || null,
        codigo_item_pai: codigoPai || null,
        produto: p.produto ?? null,
        modelo: p.modelo ?? null,
        acabamentos: p.acabamentos ?? null,
        largura: p?.dimensoes?.largura ?? null,
        altura: p?.dimensoes?.altura ?? null,
        espessura: p?.dimensoes?.espessura ?? null,
        materias_primas: Array.isArray(p.materias_primas) ? p.materias_primas : [],
      },
      fonte: 'chronos',
    },
  };
});

const body = $json.body ?? $json;
const produtos = body.produtos?.Produtos ?? [];

return produtos.map((produto, index) => {
  return {
    json: {
      os_num: body.os_num,
      folder_id: body.folder_id,
      folder_name: body.folder_name,
      cache_id: body.cache_id,
      cabecalho: body.cabecalho,
      produto,
      trello_card_index: index + 1,
    }
  };
});

