additionalFields.due:
={{ (() => {
  const data = ($json.cabecalho['Data de entrega'] || '').trim();
  const hora = ($json.cabecalho['Hora de entrega'] || '12:00').trim();
  if (!data) return '';

  const [dia, mes, ano] = data.split('/');
  const horaValida = /^\d{2}:\d{2}$/.test(hora) ? hora : '12:00';

  return `${ano}-${mes}-${dia}T${horaValida}:00-03:00`;
})() }}
